import{_ as o,c as t,o as r,ag as c}from"./chunks/framework.Bw-5EFTY.js";const h=JSON.parse('{"title":"DAG Worker Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/dag-worker/SPEC.md","filePath":"packages/dag-worker/SPEC.md"}'),i={name:"packages/dag-worker/SPEC.md"};function a(s,e,d,n,l,u){return r(),t("div",null,e[0]||(e[0]=[c('<h1 id="dag-worker-specification" tabindex="-1">DAG Worker Specification <a class="header-anchor" href="#dag-worker-specification" aria-label="Permalink to &quot;DAG Worker Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Owns the dequeue-process loop for task execution within DAG runs. Applies lease acquisition, timeout enforcement, retry logic, dead letter queue (DLQ) handling, downstream task dispatch, and DAG run finalization behavior.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Depends on <code>dag-core</code> for domain contracts, state machines, port interfaces, and error builders.</li><li>Does not define DAG definitions, API contracts, or scheduling logic.</li><li>Does not own runtime orchestration (run creation, start) -- those belong to <code>dag-runtime</code>.</li><li>Does not own projection or observability concerns.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The package has three main modules:</p><ul><li><strong>WorkerLoopService</strong> (<code>services/worker-loop-service.ts</code>): The core processing loop. Each <code>processOnce()</code> call dequeues a message, acquires a lease, executes the task via <code>ITaskExecutorPort</code>, handles success/failure paths, dispatches downstream tasks, and finalizes the DAG run when all tasks are terminal.</li><li><strong>DlqReinjectService</strong> (<code>services/dlq-reinject-service.ts</code>): Dequeues from the dead letter queue, transitions the task to retry state, and re-enqueues to the main queue.</li><li><strong>Composition factory</strong> (<code>composition/create-worker-loop-service.ts</code>): Wires <code>WorkerLoopService</code> from port dependencies and policy options.</li></ul><p>Supporting utility:</p><ul><li><code>replaceAttemptSegment(path, nextAttempt)</code> -- updates the attempt segment in an execution path array.</li></ul><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package is SSOT for:</p><ul><li><code>IWorkerLoopOptions</code> -- worker configuration (workerId, leaseDurationMs, visibilityTimeoutMs, retryEnabled, deadLetterEnabled, maxAttempts, defaultTimeoutMs)</li><li><code>IWorkerLoopResult</code> -- processing result (processed, taskRunId, retried)</li><li><code>IDlqReinjectResult</code> -- reinject result (reinjected, taskRunId)</li><li><code>IWorkerLoopDependencies</code> -- dependency injection shape for the composition factory</li><li><code>IWorkerLoopPolicyOptions</code> -- policy-level options with optional retry/DLQ flags</li></ul><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><ul><li><code>WorkerLoopService</code> -- main service class <ul><li><code>processOnce(): Promise&lt;TResult&lt;IWorkerLoopResult, IDagError&gt;&gt;</code> -- dequeue and process one task</li></ul></li><li><code>DlqReinjectService</code> -- DLQ reinject service <ul><li><code>reinjectOnce(workerId, visibilityTimeoutMs): Promise&lt;TResult&lt;IDlqReinjectResult, IDagError&gt;&gt;</code></li></ul></li><li><code>createWorkerLoopService(deps, options): WorkerLoopService</code> -- composition factory</li><li><code>replaceAttemptSegment(path, nextAttempt): string[]</code> -- execution path utility</li></ul><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ul><li><code>ITaskExecutorPort</code> (from <code>dag-core</code>) -- consumers implement this to define how tasks are executed.</li><li><code>ILeasePort</code> (from <code>dag-core</code>) -- consumers provide lease acquisition/release mechanics.</li><li><code>IQueuePort</code> (from <code>dag-core</code>) -- consumers provide queue enqueue/dequeue/ack/nack behavior.</li><li><code>IRunProgressEventReporter</code> (from <code>dag-core</code>) -- optional reporter for publishing task/run progress events.</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>All errors use <code>IDagError</code> from <code>dag-core</code> with the following codes:</p><p><strong>Lease errors</strong> (<code>category: &#39;lease&#39;</code>):</p><ul><li><code>DAG_LEASE_CONTRACT_VIOLATION</code> -- failed to acquire lease for a task run</li></ul><p><strong>Validation errors</strong> (<code>category: &#39;validation&#39;</code>):</p><ul><li><code>DAG_VALIDATION_TASK_RUN_NOT_FOUND</code> -- task run missing for dequeued message</li><li><code>DAG_VALIDATION_DAG_RUN_NOT_FOUND</code> -- DAG run missing</li><li><code>DAG_VALIDATION_NODE_NOT_FOUND</code> -- node definition missing for task</li><li><code>DAG_VALIDATION_DEFINITION_SNAPSHOT_MISSING</code> / <code>_INVALID</code> / <code>_PARSE_FAILED</code> -- snapshot errors</li><li><code>DAG_VALIDATION_DOWNSTREAM_NODE_NOT_FOUND</code> -- downstream node missing</li><li><code>DAG_VALIDATION_BINDING_*</code> -- binding resolution errors (REQUIRED, OUTPUT_KEY_MISSING, INPUT_KEY_MISSING, INPUT_KEY_CONFLICT, LIST_PAYLOAD_INVALID)</li><li><code>DAG_VALIDATION_UPSTREAM_OUTPUT_*</code> -- upstream output errors (MISSING, INVALID, PARSE_FAILED)</li><li><code>DAG_VALIDATION_DEAD_LETTER_QUEUE_NOT_CONFIGURED</code> -- DLQ enabled but not configured</li></ul><p><strong>Dispatch errors</strong> (<code>category: &#39;dispatch&#39;</code>):</p><ul><li><code>DAG_DISPATCH_ENQUEUE_RETRY_FAILED</code> -- retry enqueue failure</li><li><code>DAG_DISPATCH_ENQUEUE_DOWNSTREAM_FAILED</code> -- downstream enqueue failure</li><li><code>DAG_DISPATCH_DEAD_LETTER_ENQUEUE_FAILED</code> -- DLQ enqueue failure</li><li><code>DAG_DISPATCH_REINJECT_ENQUEUE_FAILED</code> -- reinject enqueue failure</li></ul><p><strong>Task execution errors</strong> (<code>category: &#39;task_execution&#39;</code>):</p><ul><li><code>DAG_TASK_EXECUTION_TIMEOUT</code> -- task exceeded timeout</li><li><code>DAG_TASK_EXECUTION_EXCEPTION</code> -- executor threw an exception</li><li><code>DAG_TASK_EXECUTION_FAILED</code> -- generic run failure</li></ul><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><p>No classes in this package use the <code>implements</code> keyword. All port dependencies are consumed via constructor injection.</p><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><p>None. Service classes are standalone (no <code>extends</code>).</p><h3 id="port-consumption-via-di" tabindex="-1">Port Consumption via DI <a class="header-anchor" href="#port-consumption-via-di" aria-label="Permalink to &quot;Port Consumption via DI&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Service Class</th><th>Injected Port (from dag-core)</th><th>Location</th></tr></thead><tbody><tr><td><code>WorkerLoopService</code></td><td><code>IStoragePort</code>, <code>IQueuePort</code>, <code>ILeasePort</code>, <code>ITaskExecutorPort</code>, <code>IClockPort</code></td><td><code>src/services/worker-loop-service.ts</code></td></tr><tr><td><code>DlqReinjectService</code></td><td><code>IStoragePort</code>, <code>IQueuePort</code> (x2), <code>IClockPort</code></td><td><code>src/services/dlq-reinject-service.ts</code></td></tr></tbody></table><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Consumer Class</th><th>Location</th></tr></thead><tbody><tr><td><code>IStoragePort</code> (dag-core)</td><td><code>WorkerLoopService</code>, <code>DlqReinjectService</code></td><td><code>src/services/</code></td></tr><tr><td><code>IQueuePort</code> (dag-core)</td><td><code>WorkerLoopService</code>, <code>DlqReinjectService</code></td><td><code>src/services/</code></td></tr><tr><td><code>ILeasePort</code> (dag-core)</td><td><code>WorkerLoopService</code></td><td><code>src/services/worker-loop-service.ts</code></td></tr><tr><td><code>ITaskExecutorPort</code> (dag-core)</td><td><code>WorkerLoopService</code></td><td><code>src/services/worker-loop-service.ts</code></td></tr><tr><td><code>IClockPort</code> (dag-core)</td><td><code>WorkerLoopService</code>, <code>DlqReinjectService</code></td><td><code>src/services/</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><ul><li><strong>Unit tests</strong>: <code>worker-loop-service.test.ts</code>, <code>dlq-reinject-service.test.ts</code>, <code>worker-loop-composition.test.ts</code></li><li>Tests use in-memory port implementations from <code>dag-core</code>.</li><li>Coverage focus: lease acquisition/release, success/failure paths, retry logic with attempt increment, DLQ enqueue/reinject, downstream dispatch with binding resolution, DAG run finalization (success/failure), timeout enforcement.</li><li>Run: <code>pnpm --filter @robota-sdk/dag-worker test</code></li></ul>',38)]))}const m=o(i,[["render",a]]);export{h as __pageData,m as default};
